const laws = [{"id": "labor_001", "name": "نظام العمل - الأحكام العامة", "text": "المادة الأولى: تسري أحكام هذا النظام على العقود المبرمة لأداء عمل في المملكة العربية السعودية. المادة الثانية: لا يسري هذا النظام على موظفي الحكومة والهيئات والمؤسسات العامة وعمال الزراعة والرعي الطبيعي ومن يعمل لمصلحة صاحب عمل من أفراد أسرته. المادة الثالثة: العامل كل شخص طبيعي يعمل لمصلحة صاحب عمل وتحت إدارته أو إشرافه مقابل أجر. المادة الرابعة: صاحب العمل كل شخص طبيعي أو اعتباري يستخدم عاملاً أو أكثر مقابل أجر. المادة الخامسة: عند العمل لأقل من ثلاثة أشهر يعتبر العامل في فترة تجربة ما لم يتفق على خلاف ذلك. المادة السادسة: يجب أن يكون عقد العمل مكتوباً محدداً للأجر ونوع العمل ومكانه ومدته إن كانت محددة."}, {"id": "labor_002", "name": "نظام العمل - إنهاء العقد والتعويضات", "text": "المادة الثمانون: إذا أنهى صاحب العمل العقد دون سبب مشروع وجب عليه تعويض العامل عن مدة الخدمة بواقع أجر شهر عن كل سنة من سنوات الخدمة. المادة الواحدة والثمانون: يستحق العامل مكافأة نهاية الخدمة عند انتهاء عقده بواقع أجر نصف شهر عن كل سنة من السنوات الخمس الأولى وأجر شهر عن كل سنة بعد ذلك. المادة الثانية والثمانون: يحق للعامل إنهاء عقده دون إشعار مسبق في حالات محددة منها إخلال صاحب العمل بالتزاماته التعاقدية أو إذا ثبت الغش عند التعاقد. المادة الثالثة والثمانون: للعامل الحق في إجازة سنوية مدفوعة الأجر لا تقل عن واحد وعشرين يوماً في السنة وتزداد إلى ثلاثين يوماً بعد خمس سنوات خدمة."}, {"id": "company_001", "name": "نظام الشركات - الشركة ذات المسؤولية المحدودة", "text": "المادة الأولى: الشركة ذات المسؤولية المحدودة شركة تتكون من شريك أو أكثر ولا يسأل كل منهم إلا بمقدار حصته في رأس المال. المادة الثانية: يجب ألا يقل رأس مال الشركة ذات المسؤولية المحدودة عن عشرة آلاف ريال سعودي. المادة الثالثة: تتكون الشركة من عقد تأسيس يتضمن اسم الشركة وغرضها ورأس مالها وحصص الشركاء. المادة الرابعة: تُدار الشركة بواسطة مدير أو أكثر من الشركاء أو من غيرهم. المادة الخامسة: لا يجوز للشركة إصدار أسهم أو سندات قابلة للتداول في السوق المالية. المادة السادسة: تُوزَّع الأرباح والخسائر بين الشركاء بنسبة حصصهم في رأس المال ما لم يُتفق على خلاف ذلك."}, {"id": "vat_001", "name": "نظام ضريبة القيمة المضافة", "text": "المادة الأولى: تُفرض ضريبة القيمة المضافة بنسبة خمسة عشر بالمائة على جميع السلع والخدمات المُورَّدة في المملكة العربية السعودية. المادة الثانية: يلتزم كل شخص خاضع للضريبة بالتسجيل لدى الهيئة العامة للزكاة والضريبة والجمارك إذا تجاوز حجم أعماله حد التسجيل الإلزامي. المادة الثالثة: حد التسجيل الإلزامي مائة وثمانية وثمانون ألف ريال سعودي سنوياً. المادة الرابعة: يجب على الخاضع للضريبة إصدار فاتورة ضريبية لكل عملية توريد خاضعة للضريبة. المادة الخامسة: يحق للخاضع للضريبة خصم ضريبة المدخلات المدفوعة على مشترياته من ضريبة المخرجات المستحقة على مبيعاته. المادة السادسة: تُقدَّم الإقرارات الضريبية شهرياً أو ربع سنوياً حسب حجم الأعمال."}, {"id": "data_001", "name": "نظام حماية البيانات الشخصية", "text": "المادة الأولى: يهدف هذا النظام إلى حماية البيانات الشخصية من الجمع والمعالجة غير المشروعة وصون الخصوصية. المادة الثانية: لا يجوز جمع البيانات الشخصية أو معالجتها إلا بموافقة صريحة من صاحبها أو لغرض مشروع محدد. المادة الثالثة: يحق لصاحب البيانات الاطلاع على بياناته وطلب تصحيحها أو حذفها. المادة الرابعة: يجب على الجهات المعالجة للبيانات اتخاذ التدابير التقنية والتنظيمية الكافية لحماية البيانات من الاختراق. المادة الخامسة: يُعاقب على مخالفة أحكام هذا النظام بغرامة مالية لا تتجاوز خمسة ملايين ريال سعودي. المادة السادسة: تختص الهيئة السعودية للبيانات والذكاء الاصطناعي بالإشراف على تطبيق هذا النظام."}, {"id": "cyber_001", "name": "نظام مكافحة الجرائم المعلوماتية", "text": "المادة الأولى: يُعاقب بالسجن مدة لا تزيد على سنة وبغرامة مالية لا تزيد على خمسمائة ألف ريال كل من يرتكب جريمة معلوماتية. المادة الثانية: الجريمة المعلوماتية كل فعل يُرتكب متضمناً استخدام الحاسب الآلي أو الشبكة المعلوماتية بصورة غير مشروعة. المادة الثالثة: يُعاقب بالسجن مدة لا تزيد على أربع سنوات وبغرامة لا تزيد على ثلاثة ملايين ريال كل من يصل بطريقة غير مشروعة إلى بيانات تمس النظام العام. المادة الرابعة: تُضاعف العقوبة إذا وقعت الجريمة على جهة حكومية أو بنية تحتية حيوية. المادة الخامسة: يُعاقب على إنشاء المواقع الإلكترونية التي تتضمن محتوى مخالفاً للنظام العام أو القيم الدينية."}];
const results = [];
const chunkSize = 600;
const overlap = 80;

for (const law of laws) {
  const text = law.text;
  let start = 0;
  let idx = 0;
  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    const chunk = text.substring(start, end).trim();
    if (chunk.length > 30) {
      results.push({
        json: {
          chunk_id: law.id + '_c' + idx,
          chunk_text: chunk,
          law_name: law.name,
          law_id: law.id
        }
      });
      idx++;
    }
    if (end >= text.length) break;
    start += chunkSize - overlap;
  }
}
return results;

const embedding = $json.embedding;
const prev = $('📚 تحميل وتقسيم النصوص').item.json;

if (!embedding || !Array.isArray(embedding) || embedding.length === 0) {
  return [{ json: { status: 'skip', reason: 'no embedding', chunk_id: prev.chunk_id } }];
}

const body = {
  ids: [prev.chunk_id],
  embeddings: [embedding],
  documents: [prev.chunk_text],
  metadatas: [{ law_name: prev.law_name, law_id: prev.law_id }]
};

const response = await $http.request({
  method: 'POST',
  url: 'http://chromadb:8000/api/v2/tenants/default_tenant/databases/default_database/collections/saleh_legal_knowledge/upsert',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body)
});

return [{ json: { status: 'saved', chunk_id: prev.chunk_id, law_name: prev.law_name } }];

const items = $input.all();
const saved = items.filter(i => i.json.status === 'saved').length;
const skipped = items.filter(i => i.json.status === 'skip').length;
return [{ json: { 
  total: items.length,
  saved: saved,
  skipped: skipped,
  message: `✅ تم حفظ ${saved} chunk في ChromaDB`
} }];
